1; i <= m; i++) {
num[i]
= i;
}
//
数据量小
->
递推
for (int i =
m + 1; i <= n; i++) {
int
mx = INT_MIN, mn = INT_MAX;
set<int>
s;
bool dupFlag =
false;
for
(int j = i - m; j < i; j++) {
if
(s.count(num[j])) {
dupFlag =
true;
}
s.insert(num[j]);
mx
